void main() {

    mldsa_io seed;
    uint32_t entropy[MLDSA87_ENTROPY_SIZE];
    uint32_t msg[MLDSA87_MSG_SIZE];
    uint32_t sign_rnd[MLDSA87_SIGN_RND_SIZE];

    VPRINTF(LOW, "----------------------------------------------\n");
    VPRINTF(LOW, " MLDSA KeyGen + Signing — all-zero inputs\n");
    VPRINTF(LOW, "----------------------------------------------\n");

    init_interrupts();

    // All-zero inputs
    seed.kv_intf = FALSE;
    for (int i = 0; i < MLDSA87_SEED_SIZE; i++)
        seed.data[i] = 0;
    for (int i = 0; i < MLDSA87_ENTROPY_SIZE; i++)
        entropy[i] = 0;
    for (int i = 0; i < MLDSA87_MSG_SIZE; i++)
        msg[i] = 0;
    for (int i = 0; i < MLDSA87_SIGN_RND_SIZE; i++)
        sign_rnd[i] = 0;

    // KeyGen
    mldsa_keygen_flow(seed, entropy, expected_privkey, expected_pubkey);
    mldsa_zeroize();
    cptra_intr_rcv.abr_notif = 0;

    // // Signing
    // mldsa_keygen_signing_flow(seed, msg, sign_rnd, entropy, expected_sign);
    // mldsa_zeroize();
    // cptra_intr_rcv.abr_notif = 0;

    SEND_STDOUT_CTRL(0xff);
}
